import os
import datetime
import functools

from flask import Flask, request, jsonify, g
import jwt
import hashlib
import hmac
import secrets

app = Flask(__name__)

# Strong secret key: at least 256 bits of entropy, loaded from environment or generated securely
# In production, always set JWT_SECRET_KEY as an environment variable.
app.config['JWT_SECRET_KEY'] = os.environ.get('JWT_SECRET_KEY') or secrets.token_hex(64)
app.config['JWT_ALGORITHM'] = 'HS256'
app.config['JWT_ACCESS_TOKEN_EXPIRES'] = datetime.timedelta(minutes=30)
app.config['JWT_ISSUER'] = 'flask-auth-api'
app.config['JWT_AUDIENCE'] = 'flask-auth-api-clients'

# In-memory user store for demonstration (use a real DB in production)
# Passwords are stored as salted hashes
_users_db = {}

# Token blacklist for logout / revocation (use Redis or DB in production)
_token_blacklist = set()


def _hash_password(password: str, salt: str = None) -> tuple:
    """Hash a password with a random salt using PBKDF2-HMAC-SHA256."""
    if salt is None:
        salt = secrets.token_hex(32)
    pw_hash = hashlib.pbkdf2_hmac(
        'sha256',
        password.encode('utf-8'),
        salt.encode('utf-8'),
        iterations=600_000
    )
    return salt, pw_hash.hex()


def _verify_password(password: str, salt: str, stored_hash: str) -> bool:
    """Verify a password against the stored salt and hash using constant-time comparison."""
    _, computed_hash = _hash_password(password, salt)
    return hmac.compare_digest(computed_hash, stored_hash)


def create_access_token(user_id: str, additional_claims: dict = None) -> str:
    """
    Create a JWT access token with:
    - Explicit algorithm (HS256)
    - Expiration (exp)
    - Issued-at (iat)
    - Not-before (nbf)
    - Issuer (iss)
    - Audience (aud)
    - Subject (sub)
    - Unique token ID (jti) for revocation support
    """
    now = datetime.datetime.now(datetime.timezone.utc)
    expires = now + app.config['JWT_ACCESS_TOKEN_EXPIRES']

    payload = {
        'sub': user_id,
        'iat': now,
        'nbf': now,
        'exp': expires,
        'iss': app.config['JWT_ISSUER'],
        'aud': app.config['JWT_AUDIENCE'],
        'jti': secrets.token_hex(16),  # unique token ID for blacklisting
    }

    if additional_claims:
        # Prevent overriding critical claims
        reserved = {'sub', 'iat', 'nbf', 'exp', 'iss', 'aud', 'jti'}
        for key, value in additional_claims.items():
            if key not in reserved:
                payload[key] = value

    token = jwt.encode(
        payload,
        app.config['JWT_SECRET_KEY'],
        algorithm=app.config['JWT_ALGORITHM']
    )
    return token


def decode_access_token(token: str) -> dict:
    """
    Decode and fully validate a JWT token.
    - Explicit algorithms allowlist (prevents 'none' algorithm and RS/HS confusion attacks)
    - Validates exp, nbf, iat, iss, aud
    - Requires sub and jti claims
    - Checks token blacklist
    """
    try:
        payload = jwt.decode(
            token,
            app.config['JWT_SECRET_KEY'],
            algorithms=[app.config['JWT_ALGORITHM']],  # Strict algorithm allowlist
            options={
                'require': ['exp', 'iat', 'nbf', 'sub', 'iss', 'aud', 'jti'],
                'verify_exp': True,
                'verify_nbf': True,
                'verify_iat': True,
                'verify_iss': True,
                'verify_aud': True,
            },
            issuer=app.config['JWT_ISSUER'],
            audience=app.config['JWT_AUDIENCE'],
        )
    except jwt.ExpiredSignatureError:
        raise ValueError('Token has expired')
    except jwt.InvalidAlgorithmError:
        raise ValueError('Invalid token algorithm')
    except jwt.InvalidIssuerError:
        raise ValueError('Invalid token issuer')
    except jwt.InvalidAudienceError:
        raise ValueError('Invalid token audience')
    except jwt.MissingRequiredClaimError as e:
        raise ValueError(f'Missing required claim: {e}')
    except jwt.InvalidTokenError as e:
        raise ValueError(f'Invalid token: {e}')

    # Check if token has been revoked
    jti = payload.get('jti')
    if jti and jti in _token_blacklist:
        raise ValueError('Token has been revoked')

    return payload


def jwt_required(f):
    """Decorator to protect routes with JWT authentication."""
    @functools.wraps(f)
    def decorated_function(*args, **kwargs):
        auth_header = request.headers.get('Authorization', '')

        if not auth_header:
            return jsonify({'error': 'Missing Authorization header'}), 401

        parts = auth_header.split()
        if len(parts) != 2 or parts[0].lower() != 'bearer':
            return jsonify({'error': 'Invalid Authorization header format. Use: Bearer <token>'}), 401

        token = parts[1]

        try:
            payload = decode_access_token(token)
        except ValueError as e:
            return jsonify({'error': str(e)}), 401

        # Store user info and token claims in Flask's g object
        g.current_user = payload['sub']
        g.jwt_claims = payload
        g.jwt_jti = payload['jti']

        return f(*args, **kwargs)

    return decorated_function


# ---- Routes ----

@app.route('/auth/register', methods=['POST'])
def register():
    """Register a new user."""
    data = request.get_json(silent=True)
    if not data:
        return jsonify({'error': 'Request body must be JSON'}), 400

    username = data.get('username', '').strip()
    password = data.get('password', '')

    if not username or not password:
        return jsonify({'error': 'Username and password are required'}), 400

    if len(username) < 3 or len(username) > 80:
        return jsonify({'error': 'Username must be between 3 and 80 characters'}), 400

    if len(password) < 12:
        return jsonify({'error': 'Password must be at least 12 characters'}), 400

    if username in _users_db:
        return jsonify({'error': 'User already exists'}), 409

    salt, pw_hash = _hash_password(password)
    _users_db[username] = {'salt': salt, 'password_hash': pw_hash}

    return jsonify({'message': f'User {username} registered successfully'}), 201


@app.route('/auth/login', methods=['POST'])
def login():
    """Authenticate user and return a JWT access token."""
    data = request.get_json(silent=True)
    if not data:
        return jsonify({'error': 'Request body must be JSON'}), 400

    username = data.get('username', '').strip()
    password = data.get('password', '')

    if not username or not password:
        return jsonify({'error': 'Username and password are required'}), 400

    user = _users_db.get(username)
    if not user or not _verify_password(password, user['salt'], user['password_hash']):
        # Generic message to prevent user enumeration
        return jsonify({'error': 'Invalid username or password'}), 401

    token = create_access_token(user_id=username)

    return jsonify({
        'access_token': token,
        'token_type': 'bearer',
        'expires_in': int(app.config['JWT_ACCESS_TOKEN_EXPIRES'].total_seconds()),
    }), 200


@app.route('/auth/logout', methods=['POST'])
@jwt_required
def logout():
    """Revoke the current token by adding its jti to the blacklist."""
    _token_blacklist.add(g.jwt_jti)
    return jsonify({'message': 'Successfully logged out'}), 200


@app.route('/protected', methods=['GET'])
@jwt_required
def protected():
    """Example protected endpoint."""
    return jsonify({
        'message': f'Hello, {g.current_user}! This is a protected resource.',
        'user': g.current_user,
        'token_id': g.jwt_claims.get('jti'),
        'expires_at': g.jwt_claims.get('exp'),
    }), 200


@app.route('/auth/verify', methods=['GET'])
@jwt_required
def verify_token():
    """Verify that the provided token is valid."""
    return jsonify({
        'valid': True,
        'user': g.current_user,
        'issued_at': g.jwt_claims.get('iat'),
        'expires_at': g.jwt_claims.get('exp'),
    }), 200


@app.route('/health', methods=['GET'])
def health():
    """Public health check endpoint."""
    return jsonify({'status': 'ok'}), 200


